SELECT request_id, source_ip, response_status
FROM network_requests
WHERE response_status = 200;

SELECT COUNT(*) AS hipaa_violations_count
FROM compliance_violations
WHERE violation_type = 'HIPAA';

SELECT violation_id, request_id, violation_description
FROM compliance_violations
WHERE violation_type = 'GDPR';

SELECT COUNT(*) AS request_count
FROM network_requests
WHERE response_status = 404;

SELECT incident_type
FROM security_incidents
WHERE incident_id = 1;

SELECT request_id FROM security_incidents
UNION
SELECT request_id FROM compliance_violations;

SELECT incident_id, incident_type, incident_description
FROM security_incidents
WHERE status = 'open' AND severity = 'high';
